import{c as i,Q as n,j as t,m as a}from"./chunks/framework.BPKcPtvA.js";const g=JSON.parse('{"title":"Orchestration & State Transitions","description":"Technical specification of orchestrator states, transition tables, and decision gates","frontmatter":{"title":"Orchestration & State Transitions","description":"Technical specification of orchestrator states, transition tables, and decision gates","keywords":"state machine, workflow steps, system state, state transition, decision logic","robots":"index, follow"},"headers":[],"relativePath":"en/flows/index.md","filePath":"en/flows/index.md","lastUpdated":null}'),e={name:"en/flows/index.md"};function l(o,s,r,d,c,p){return n(),t("div",null,[...s[0]||(s[0]=[a(`<h1 id="🔄-orchestration-state-transitions" tabindex="-1">🔄 Orchestration &amp; State Transitions <a class="header-anchor" href="#🔄-orchestration-state-transitions" aria-label="Permalink to &quot;🔄 Orchestration &amp; State Transitions&quot;">​</a></h1><p>The runtime cycle of the orchestrator is formally modeled as a <strong>Finite State Machine (FSM)</strong> with strictly defined states and transition triggers. This document explains each state shift and evaluation gate inside the system.</p><hr><h2 id="🗺️-system-state-machine-diagram" tabindex="-1">🗺️ System State Machine Diagram <a class="header-anchor" href="#🗺️-system-state-machine-diagram" aria-label="Permalink to &quot;🗺️ System State Machine Diagram&quot;">​</a></h2><p>The diagram below maps the FSM states traversed from request submission to memory audit logging:</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">stateDiagram-v2</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    [*] --&gt; Idle : System Initialization</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    </span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    state Idle {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        [*] --&gt; VerifyingIdentity : Request Submitted</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        VerifyingIdentity --&gt; IdentityVerified : Success (GCP &amp; MongoDB locks match)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        VerifyingIdentity --&gt; [*] : Identity Mismatch (Halt)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Idle --&gt; LoadingContext : Reload past ELO and traces</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    LoadingContext --&gt; Classifying : Tagging &amp; Cosine similarity lookups</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Classifying --&gt; Planning : build_initial_plan()</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    </span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    state Arena_Debate {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        Planning --&gt; Round_1_Analyst : Trigger run_debate()</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        Round_1_Analyst --&gt; Round_2_Solution</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        Round_2_Solution --&gt; Round_3_Critic</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        Round_3_Critic --&gt; Round_4_Security</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        Round_4_Security --&gt; Round_5_Optimizer</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        Round_5_Optimizer --&gt; Multi_Pass_Check : Evaluate consensus confidence</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        Multi_Pass_Check --&gt; Round_2_Solution : Re-debate (Rule-of-3 if confidence &lt; 0.8)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        Multi_Pass_Check --&gt; Aggregating : Confidence threshold met / turn limit hit</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    </span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    state Aggregation_Engine {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        Aggregating --&gt; CalculatingConsensus</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        CalculatingConsensus --&gt; ELODuels : Resolve Weights &amp; duels</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        ELODuels --&gt; ResolvingDecision</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ResolvingDecision --&gt; SandboxedExecution : PROCEED (Consensus reached)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ResolvingDecision --&gt; Blocked : REJECT / VETO (Security anomaly found)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    </span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    state SandboxedExecution {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        [*] --&gt; RunningTasks : execute_plan()</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        RunningTasks --&gt; ValidationCheck : Build execution report</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        </span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        state ValidationCheck {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">            [*] --&gt; AssertingOutcomes</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">            AssertingOutcomes --&gt; Success : All tasks returned success</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">            AssertingOutcomes --&gt; Failure : Task returned error</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        }</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        Failure --&gt; SelfHealingActive : Trigger Self-Healing</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        SelfHealingActive --&gt; RunningTasks : Repaired plan loaded</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        SelfHealingActive --&gt; RollbackActive : Repair aborted / failed</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        RollbackActive --&gt; [*] : Rollback complete</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Success --&gt; StoringMemory : store_all_in_memory()</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Blocked --&gt; StoringMemory</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    StoringMemory --&gt; Auditing : audit_log()</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Auditing --&gt; [*] : Output results &amp; trace_id</span></span></code></pre></div><hr><h2 id="📊-state-transition-specifications" tabindex="-1">📊 State Transition Specifications <a class="header-anchor" href="#📊-state-transition-specifications" aria-label="Permalink to &quot;📊 State Transition Specifications&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Initial State</th><th>Event / Triggering Condition</th><th>Next State</th><th>Functional Description</th></tr></thead><tbody><tr><td><strong><code>Idle</code></strong></td><td>Request submitted by Client</td><td><strong><code>VerifyingIdentity</code></strong></td><td>Initiates zero-trust checking inside <code>IdentityGuard</code>.</td></tr><tr><td><strong><code>VerifyingIdentity</code></strong></td><td>Workspace variables mismatch</td><td><strong><code>Aborted</code></strong></td><td>Halts execution immediately (<code>sys.exit(1)</code>).</td></tr><tr><td><strong><code>Planning</code></strong></td><td>Baseline plan drafted</td><td><strong><code>Round_1_Analyst</code></strong></td><td>Commences turn-based adversarial debate rounds.</td></tr><tr><td><strong><code>Multi_Pass_Check</code></strong></td><td>Consensus $&lt; 0.8$ and turns $&lt; 3$</td><td><strong><code>Round_2_Solution</code></strong></td><td>Solution agent receives Critic reviews and refines plan.</td></tr><tr><td><strong><code>ResolvingDecision</code></strong></td><td>Security confidence $\\ge 0.9$</td><td><strong><code>Blocked</code></strong></td><td><strong>VETO!</strong> Immediate rejection of unsafe operations.</td></tr><tr><td><strong><code>ValidationCheck</code></strong></td><td>Task returns exit code $\\ne 0$</td><td><strong><code>SelfHealingActive</code></strong></td><td>Activates the autonomous self-healing diagnostics.</td></tr><tr><td><strong><code>SelfHealingActive</code></strong></td><td>Critic fails to diagnose failure</td><td><strong><code>RollbackActive</code></strong></td><td>Runs reverse-rollback operations.</td></tr><tr><td><strong><code>Success</code></strong></td><td>All validations passed</td><td><strong><code>StoringMemory</code></strong></td><td>Commits outputs to local SQLite and cloud Atlas collections.</td></tr></tbody></table><hr><h2 id="⚖️-decision-rules-for-proceed-and-veto-transitions" tabindex="-1">⚖️ Decision Rules for Proceed and Veto Transitions <a class="header-anchor" href="#⚖️-decision-rules-for-proceed-and-veto-transitions" aria-label="Permalink to &quot;⚖️ Decision Rules for Proceed and Veto Transitions&quot;">​</a></h2><p>When transitioning from <strong><code>ResolvingDecision</code></strong> to execution runs, the consensus engine validates the following criteria:</p><ol><li><strong>Transition to <code>Blocked</code> (REJECT):</strong><ul><li>If the Security Agent flags the plan with a confidence score $\\ge 0.9$ (e.g. static regex flags SQL Injection attempts).</li><li>If the aggregate weighted consensus confidence score remains $&lt; 0.6$ after all refinement passes are exhausted.</li></ul></li><li><strong>Transition to <code>SandboxedExecution</code> (PROCEED):</strong><ul><li>If the aggregate consensus confidence is $\\ge 0.6$ and no active security block is triggered.</li></ul></li></ol>`,13)])])}const E=i(e,[["render",l]]);export{g as __pageData,E as default};
